#!/usr/bin/env node
// scaffold-day8.mjs - Apply Day 8 changes to the headcount repo.
// Run from the repo root: node scaffold-day8.mjs
//
// Day 8 = Five fixes:
//   1. Standup tab in dashboard (you can finally read standups in the UI)
//   2. Time grounding in standup + CEO brief prompts (kills the 'Day 3 of Q1' loop)
//   3. Schema cache FK fix (silences the [standup] department join warning)
//   4. CLI invocation guard fix for seeds (Windows compatibility)
//   5. @types/node in shared package (handled in runbook, not this scaffold)
//
// IMPORTANT:
//   - This OVERWRITES files. Commit your current state first.
//   - It does NOT run the database migration. Run 0011_day8.sql in
//     the Supabase SQL editor manually after this scaffold completes.
//   - It does NOT install @types/node. See the runbook.

import { mkdirSync, writeFileSync } from "node:fs";
import { dirname, resolve } from "node:path";

const ROOT = process.cwd();

function writeFile(relPath, b64) {
  const full = resolve(ROOT, relPath);
  mkdirSync(dirname(full), { recursive: true });
  const buf = Buffer.from(b64, "base64");
  writeFileSync(full, buf);
  console.log(`  + ${relPath} (${buf.length} bytes)`);
}

console.log("");
console.log("Applying Day 8 to: " + ROOT);
console.log("");

writeFile('apps/dashboard/app/page.tsx', '');
writeFile('apps/orchestrator/src/rituals/ceo-brief.ts', '');
writeFile('apps/orchestrator/src/rituals/standup.ts', '');
writeFile('apps/orchestrator/src/seed/day7-bulk-specialists.ts', '');
writeFile('apps/orchestrator/src/seed/day7-org-restructure.ts', '');
writeFile('supabase/migrations/0011_day8.sql', '');

console.log("");
console.log("Done. Wrote 6 files (104955 bytes total).");
console.log("");
console.log("Next steps:");
console.log("  1. Run supabase/migrations/0011_day8.sql in the Supabase SQL editor");
console.log("  2. cd packages/shared && pnpm add -D @types/node");
console.log("  3. cd ../.. && pnpm --filter @headcount/shared exec npx tsc src/schema.ts \\");
console.log("       --outDir dist --module esnext --target es2022 \\");
console.log("       --moduleResolution bundler --skipLibCheck --declaration --esModuleInterop");
console.log("  4. Restart the orchestrator and dashboard");
console.log("");
